using UnityEngine;

/// <summary>
/// Motivo de conclusão de um desafio — usado por <see cref="ChallengeManager.OnChallengeEnded"/>
/// (HUD, Tarefa #12) e por activadores (Tarefa #11).
/// </summary>
public enum ChallengeEndReason
{
    /// <summary>Todos os objectivos "required" foram cumpridos.</summary>
    Sucesso,

    /// <summary>Tempo esgotado ou uma "failCondition" foi accionada.</summary>
    Falha,

    /// <summary>Cancelado manualmente (ex: o jogador saiu da zona/portal) — sem recompensa nem registo de tempo, sem ecrã "FALHOU".</summary>
    Abandonado,
}

/// <summary>
/// Gestor de Desafios (Sistema de Missões/Desafios) — controlador runtime do
/// desafio actualmente activo, no mesmo padrão singleton/auto-fallback de
/// MissionManager/AudioManager/GameVariables.
///
/// Não guarda configuração (vive em <see cref="ChallengeDefinition"/>) nem é
/// responsável por UI/HUD (Tarefa #12) — apenas:
///
/// - Inicia/termina o desafio activo (<see cref="StartChallenge"/>/<see cref="EndChallenge"/>/<see cref="AbandonChallenge"/>).
/// - A cada frame, avança o cronómetro (se 'hasTimeLimit'), verifica
///   <see cref="ChallengeFailCondition"/>s e <see cref="ChallengeObjective"/>s
///   (Tarefa #10) e termina o desafio com sucesso/falha automaticamente.
/// - Define <see cref="ChallengeDefinition.ActiveVariable"/>/<see cref="ChallengeDefinition.CompletedVariable"/>
///   em GameVariables.
/// - Liga ao sistema antigo de "desafio opcional por área"
///   (<see cref="ChallengeDefinition.optionalChallengeArea"/> →
///   PlayerProgress.MarkChallengeDiscovered/MarkChallengeCompleted).
/// - Concede recompensas (primária na 1ª conclusão, secundária em repetições)
///   e regista o melhor tempo (PlayerProgress.completedChallengeIds/challengeRecords).
/// - Aplica <see cref="ChallengeDefinition.endBehavior"/> (teleporta o player
///   de volta à posição de entrada, se "VoltarParaEntrada").
/// - Expõe <see cref="IsItemUsageRestricted"/>/<see cref="IsAbilityRestricted"/>
///   para PlayerItemUser/AbilityRouter (só têm efeito com 'hasTimeLimit', tal
///   como documentado em ChallengeDefinition/ChallengeDefinitionEditor).
/// - Expõe <see cref="IsApoloTrialActive"/>/<see cref="RestartApoloTrial"/> para
///   a Provação de Apolo (Tarefa #15) reiniciar o desafio ao morrer, em vez de
///   tratar como morte normal.
///
/// Música: ao iniciar, se 'challengeMusic' estiver definida, substitui o BGM da
/// área (AudioManager.PlayBGM). Ao terminar, restaura o BGM da área via
/// AudioManager.RefreshActiveZones() — a música de SUCESSO/FALHA (Tarefa #12)
/// é responsabilidade do HUD, que pode tocá-la antes desta restauração.
/// </summary>
public class ChallengeManager : MonoBehaviour
{
    public static ChallengeManager Instance { get; private set; }

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons").
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(ChallengeManager) + " (Fallback)");
        var instance = go.AddComponent<ChallengeManager>();
        instance.isAutoFallback = true;
    }

    // ---------------- Eventos (HUD/activadores) ----------------

    /// <summary>Disparado quando um desafio é iniciado com sucesso (StartChallenge).</summary>
    public static event System.Action<ChallengeDefinition> OnChallengeStarted;

    /// <summary>
    /// Disparado quando o desafio activo termina, por qualquer motivo
    /// (<see cref="ChallengeEndReason"/>). "message" é a mensagem de falha
    /// (ChallengeFailCondition.failMessage ou "Tempo esgotado!"), ou null.
    /// </summary>
    public static event System.Action<ChallengeDefinition, ChallengeEndReason, string> OnChallengeEnded;

    // Task #11: limpa subscribers ao entrar em Play Mode, mesmo com
    // "Enter Play Mode Options > Domain Reload" desactivado — sem isto,
    // handlers de objectos destruídos da sessão anterior sobreviveriam
    // (mesmo padrão de PlayerLocator/GamePauseUtil/WheelTimeScaleUtil).
    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.SubsystemRegistration)]
    private static void ResetStaticEvents()
    {
        OnChallengeStarted = null;
        OnChallengeEnded = null;
        OnPhaseAdvanced = null;
    }

    // ---------------- Estado ----------------

    /// <summary>Desafio actualmente activo, ou null se nenhum.</summary>
    public ChallengeDefinition CurrentChallenge { get; private set; }

    /// <summary>True se há um desafio activo.</summary>
    public bool IsActive => CurrentChallenge != null;

    /// <summary>Tempo decorrido desde o início do desafio activo, em segundos.</summary>
    public float ElapsedSeconds { get; private set; }

    /// <summary>Tempo restante do desafio (modo normal) ou da fase actual (modo fases). 0 se não tiver limite de tempo activo.</summary>
    public float RemainingSeconds
    {
        get
        {
            if (!IsActive) return 0f;
            var phase = CurrentPhase;
            if (phase != null && phase.hasTimeLimit)
                return Mathf.Max(0f, phase.timeLimitSeconds - _phaseElapsedSeconds);
            if (CurrentChallenge.hasTimeLimit)
                return Mathf.Max(0f, CurrentChallenge.timeLimitSeconds - ElapsedSeconds);
            return 0f;
        }
    }

    /// <summary>Tempo decorrido na fase actual (apenas em modo fases; caso contrário igual a ElapsedSeconds).</summary>
    public float PhaseElapsedSeconds => _currentPhaseIndex >= 0 ? _phaseElapsedSeconds : ElapsedSeconds;

    /// <summary>Tempo do último desafio concluído com SUCESSO (segundos) — válido durante/depois de OnChallengeEnded(Sucesso). 0 antes da primeira conclusão.</summary>
    public float LastCompletionTimeSeconds { get; private set; }

    /// <summary>True se 'LastCompletionTimeSeconds' bateu o recorde pessoal anterior (apenas desafios com 'hasTimeLimit' — ver PlayerProgress.TryRecordChallengeTime). Usado pelo ecrã de SUCESSO (Tarefa #12/#13) para mostrar "Novo Recorde!".</summary>
    public bool LastCompletionIsNewRecord { get; private set; }

    private bool _hasEntryPosition;
    private Vector3 _entryPosition;

    // Fases da Provação de Apolo
    private int _currentPhaseIndex = -1;
    private float _phaseElapsedSeconds;

    /// <summary>Índice da fase actual da Provação de Apolo (0-based). -1 se o desafio não usa fases.</summary>
    public int CurrentPhaseIndex => _currentPhaseIndex;

    /// <summary>Fase actual da Provação de Apolo, ou null se o desafio não usa fases.</summary>
    public ApoloTrialPhase CurrentPhase =>
        CurrentChallenge != null
        && _currentPhaseIndex >= 0
        && _currentPhaseIndex < CurrentChallenge.apoloPhases.Count
            ? CurrentChallenge.apoloPhases[_currentPhaseIndex]
            : null;

    /// <summary>Número total de fases do desafio activo (0 se não usa fases).</summary>
    public int TotalPhases => CurrentChallenge?.apoloPhases?.Count ?? 0;

    /// <summary>Disparado quando a fase avança (anterior → nova). Parâmetros: fase anterior (0-based), nova fase (0-based).</summary>
    public static event System.Action<int, int> OnPhaseAdvanced;

    /// <summary>Formata "seconds" como "MM:SS" (arredondado para cima) — usado pelo HUD e pelo ecrã de resultado.</summary>
    public static string FormatTime(float seconds)
    {
        int total = Mathf.Max(0, Mathf.CeilToInt(seconds));
        int minutes = total / 60;
        int secs = total % 60;
        return $"{minutes:00}:{secs:00}";
    }

    // ---------------- Início ----------------

    /// <summary>
    /// Inicia "challenge". Devolve false (sem efeito) se já houver um desafio
    /// activo, ou se "currentForm" não puder iniciar este desafio
    /// (ChallengeDefinition.IsFormAllowed) — o activador (Tarefa #11) decide o
    /// que mostrar ao jogador nesse caso (ex: mensagem "esta forma não pode
    /// entrar aqui").
    /// </summary>
    /// <param name="challenge">Desafio a iniciar.</param>
    /// <param name="currentForm">Forma actual do player, para verificar restrições (opcional — null = sem verificação).</param>
    /// <param name="entryPosition">Posição a que o player volta no fim, se 'endBehavior' = VoltarParaEntrada (opcional).</param>
    public bool StartChallenge(ChallengeDefinition challenge, AnimalFormData currentForm = null, Vector3? entryPosition = null)
    {
        if (challenge == null) return false;

        if (IsActive)
        {
            Debug.LogWarning($"[ChallengeManager] Tentativa de iniciar \"{challenge.challengeId}\" enquanto \"{CurrentChallenge.challengeId}\" ainda está activo — ignorado.");
            return false;
        }

        if (currentForm != null && !challenge.IsFormAllowed(currentForm))
            return false;

        CurrentChallenge = challenge;
        ElapsedSeconds = 0f;
        _phaseElapsedSeconds = 0f;

        _hasEntryPosition = entryPosition.HasValue;
        _entryPosition = entryPosition ?? Vector3.zero;

        // Fases (Provação de Apolo)
        bool hasPhases = challenge.apoloPhases != null && challenge.apoloPhases.Count > 0;
        if (hasPhases)
        {
            _currentPhaseIndex = 0;
            BeginPhase(0);
        }
        else
        {
            _currentPhaseIndex = -1;
            ResetObjectivesAndFailConditions(challenge);
        }

        GameVariables.Instance?.SetBool(challenge.ActiveVariable, true);

        if (challenge.optionalChallengeArea != null)
            PlayerProgress.Instance?.MarkChallengeDiscovered(challenge.optionalChallengeArea);

        if (challenge.challengeMusic != null)
            AudioManager.Instance?.PlayBGM(challenge.challengeMusic);

        OnChallengeStarted?.Invoke(challenge);
        return true;
    }

    private void ResetObjectivesAndFailConditions(ChallengeDefinition challenge)
    {
        if (challenge.objectives != null)
            foreach (var objective in challenge.objectives)
                objective?.ResetState();

        if (challenge.failConditions != null)
            foreach (var failCondition in challenge.failConditions)
                failCondition?.ResetState();
    }

    private void BeginPhase(int index)
    {
        if (CurrentChallenge == null || index < 0 || index >= CurrentChallenge.apoloPhases.Count) return;

        var phase = CurrentChallenge.apoloPhases[index];
        _currentPhaseIndex = index;
        _phaseElapsedSeconds = 0f;

        // Reset phase objectives and fail conditions.
        if (phase.objectives != null)
            foreach (var obj in phase.objectives) obj?.ResetState();
        if (phase.failConditions != null)
            foreach (var fc in phase.failConditions) fc?.ResetState();

        // Teleport player to phase spawn point, if set.
        if (phase.phaseSpawnPoint != null)
        {
            var playerT = PlayerLocator.Find();
            if (playerT != null)
            {
                var rb = playerT.GetComponent<Rigidbody2D>();
                if (rb != null) { rb.position = phase.phaseSpawnPoint.position; rb.linearVelocity = Vector2.zero; }
                else playerT.position = phase.phaseSpawnPoint.position;
            }
        }

        // Switch music if phase overrides it.
        if (phase.phaseMusic != null)
            AudioManager.Instance?.PlayBGM(phase.phaseMusic);
        else if (CurrentChallenge.challengeMusic != null)
            AudioManager.Instance?.PlayBGM(CurrentChallenge.challengeMusic);
    }

    // ---------------- Loop ----------------

    private void Update()
    {
        if (!IsActive) return;

        var challenge = CurrentChallenge;
        // Task 9.1: usar tempo não escalado para que abrir a roda (timeScale 0.2)
        // não abrande o cronómetro — previne exploração em corridas/Provações.
        ElapsedSeconds += Time.unscaledDeltaTime;

        // Modo fases (Provação de Apolo com apoloPhases configuradas)
        if (_currentPhaseIndex >= 0)
        {
            UpdatePhase(challenge);
            return;
        }

        // Modo normal (objectivos planos no nível raiz)
        if (challenge.hasTimeLimit && ElapsedSeconds >= challenge.timeLimitSeconds)
        {
            EndChallenge(ChallengeEndReason.Falha, "Tempo esgotado!");
            return;
        }

        if (challenge.failConditions != null)
        {
            foreach (var failCondition in challenge.failConditions)
            {
                if (failCondition != null && failCondition.IsFailed())
                {
                    EndChallenge(ChallengeEndReason.Falha, failCondition.failMessage);
                    return;
                }
            }
        }

        if (AllRequiredObjectivesComplete(challenge))
            EndChallenge(ChallengeEndReason.Sucesso, null);
    }

    private void UpdatePhase(ChallengeDefinition challenge)
    {
        var phase = CurrentPhase;
        if (phase == null)
        {
            // Sem mais fases — desafio concluído.
            EndChallenge(ChallengeEndReason.Sucesso, null);
            return;
        }

        _phaseElapsedSeconds += Time.unscaledDeltaTime;

        // Tempo da fase esgotado.
        if (phase.hasTimeLimit && _phaseElapsedSeconds >= phase.timeLimitSeconds)
        {
            EndChallenge(ChallengeEndReason.Falha, "Tempo esgotado!");
            return;
        }

        // Condições de falha da fase.
        if (phase.failConditions != null)
        {
            foreach (var fc in phase.failConditions)
            {
                if (fc != null && fc.IsFailed())
                {
                    EndChallenge(ChallengeEndReason.Falha, fc.failMessage);
                    return;
                }
            }
        }

        // Objectivos da fase cumpridos → avançar.
        if (AllPhaseObjectivesComplete(phase))
        {
            int prevIndex = _currentPhaseIndex;
            int nextIndex = _currentPhaseIndex + 1;

            if (nextIndex >= challenge.apoloPhases.Count)
            {
                // Última fase concluída → sucesso.
                EndChallenge(ChallengeEndReason.Sucesso, null);
            }
            else
            {
                OnPhaseAdvanced?.Invoke(prevIndex, nextIndex);
                BeginPhase(nextIndex);
            }
        }
    }

    private bool AllPhaseObjectivesComplete(ApoloTrialPhase phase)
    {
        if (phase.objectives == null || phase.objectives.Count == 0) return false;

        bool hasRequired = false;
        foreach (var obj in phase.objectives)
        {
            if (obj == null || !obj.required) continue;
            hasRequired = true;
            if (!obj.IsComplete()) return false;
        }
        return hasRequired;
    }

    private bool AllRequiredObjectivesComplete(ChallengeDefinition challenge)
    {
        if (challenge.objectives == null || challenge.objectives.Count == 0) return false;

        bool hasRequired = false;

        foreach (var objective in challenge.objectives)
        {
            if (objective == null || !objective.required) continue;

            hasRequired = true;
            if (!objective.IsComplete()) return false;
        }

        return hasRequired;
    }

    // ---------------- Fim ----------------

    /// <summary>
    /// Termina o desafio activo com "reason" (Sucesso/Falha) — aplica variáveis,
    /// persistência, recompensas, comportamento de fim e dispara
    /// <see cref="OnChallengeEnded"/>. Sem efeito se não houver desafio activo.
    /// </summary>
    public void EndChallenge(ChallengeEndReason reason, string message)
    {
        if (!IsActive) return;

        var challenge = CurrentChallenge;
        GameVariables.Instance?.SetBool(challenge.ActiveVariable, false);

        if (reason == ChallengeEndReason.Sucesso)
            HandleSuccess(challenge);

        // Restaura a música da área agora, EXCEPTO se o ecrã de
        // SUCESSO/FALHA (ChallengeResultUI, Tarefa #12) for tocar a sua
        // própria música ('successMusic'/'failMusic') — nesse caso é o
        // próprio ChallengeResultUI que restaura no fim do seu overlay.
        bool resultScreenHasMusic =
            (reason == ChallengeEndReason.Sucesso && challenge.successMusic != null) ||
            (reason == ChallengeEndReason.Falha && challenge.failMusic != null);

        if (challenge.challengeMusic != null && !resultScreenHasMusic)
            AudioManager.Instance?.RefreshActiveZones();

        ApplyEndBehavior(challenge);

        CurrentChallenge = null;
        ElapsedSeconds = 0f;
        _phaseElapsedSeconds = 0f;
        _currentPhaseIndex = -1;
        _hasEntryPosition = false;

        OnChallengeEnded?.Invoke(challenge, reason, message);
    }

    /// <summary>
    /// Cancela o desafio activo sem sucesso/falha — sem recompensa, sem
    /// registo de tempo, sem alterar "completedChallengeIds"/CompletedVariable,
    /// e sem ecrã "FALHOU" (apenas <see cref="ChallengeEndReason.Abandonado"/>
    /// para o HUD/activador). Útil quando o jogador sai da zona/portal antes de
    /// terminar.
    /// </summary>
    public void AbandonChallenge()
    {
        if (!IsActive) return;
        EndChallenge(ChallengeEndReason.Abandonado, null);
    }

    private void HandleSuccess(ChallengeDefinition challenge)
    {
        var progress = PlayerProgress.Instance;

        bool firstTime = progress == null || !progress.HasCompletedChallenge(challenge.challengeId);

        GameVariables.Instance?.SetBool(challenge.CompletedVariable, true);
        progress?.MarkChallengeIdCompleted(challenge.challengeId);

        LastCompletionTimeSeconds = ElapsedSeconds;
        LastCompletionIsNewRecord = challenge.hasTimeLimit && progress != null && progress.TryRecordChallengeTime(challenge.challengeId, ElapsedSeconds);

        if (challenge.optionalChallengeArea != null)
            progress?.MarkChallengeCompleted(challenge.optionalChallengeArea);

        var reward = firstTime ? challenge.primaryReward
            : (challenge.hasSecondaryReward ? challenge.secondaryReward : null);

        GrantReward(reward);

        // Verifica emblemas após desafio concluído — pode desbloquear o Emblema
        // de Apolo (se isApoloTrial) ou o Emblema de Gaia (se este desafio
        // completava a percentagem) (Tarefa #32).
        EmblemManager.Instance?.CheckAll();
    }

    private void GrantReward(ChallengeReward reward)
    {
        if (reward == null || !reward.HasAnything) return;

        var progress = PlayerProgress.Instance;

        // Itens, Sementes, Runas.
        if (progress != null)
        {
            if (reward.itemRewards != null)
            {
                foreach (var entry in reward.itemRewards)
                {
                    if (entry == null || entry.item == null) continue;
                    progress.AddItem(entry.item, entry.amount);
                }
            }

            if (reward.sementes > 0) progress.GiveSementes(reward.sementes);
            if (reward.runasDeGaia > 0) progress.GiveRunasDeGaia(reward.runasDeGaia);
            if (reward.runasDeApolo > 0) progress.GiveRunasDeApolo(reward.runasDeApolo);
        }

        // Eventos de NPC — cenas de libertação, animações narrativas, etc.
        // Cada entrada dispara imediatamente via TriggerEventById; se o NPC já
        // estiver a correr um evento, o trigger é ignorado nesse NPC (usar
        // Action_ActivateNpcEvent → Update natural para casos encadeados).
        if (reward.npcEventRewards != null)
        {
            foreach (var entry in reward.npcEventRewards)
            {
                if (entry == null || string.IsNullOrEmpty(entry.npcId)) continue;

                var npc = NpcController.FindById(entry.npcId);
                if (npc == null)
                {
                    Debug.LogWarning($"[ChallengeManager] GrantReward: NPC '{entry.npcId}' não encontrado na cena — evento '{entry.npcEventId}' ignorado.");
                    continue;
                }

                npc.TriggerEventById(entry.npcEventId);
            }
        }
    }

    private void ApplyEndBehavior(ChallengeDefinition challenge)
    {
        if (challenge.endBehavior != ChallengeEndBehavior.VoltarParaEntrada || !_hasEntryPosition) return;

        var playerT = PlayerLocator.Find();
        if (playerT == null) return;

        var rb = playerT.GetComponent<Rigidbody2D>();
        if (rb != null)
        {
            rb.position = _entryPosition;
            rb.linearVelocity = Vector2.zero;
        }
        else
        {
            playerT.position = _entryPosition;
        }
    }

    // ---------------- Restrições Durante o Desafio ----------------

    /// <summary>
    /// True se a troca de forma está bloqueada agora (FormSwitcher).
    /// Activo sempre que o desafio activo tiver 'lockFormDuringChallenge' —
    /// sem necessidade de 'hasTimeLimit' (portais de forma específica são por
    /// natureza sem timeout, mas o bloqueio é permanente enquanto o desafio
    /// estiver activo).
    /// </summary>
    public bool IsFormSwitchingLocked =>
        IsActive && CurrentChallenge != null && CurrentChallenge.lockFormDuringChallenge;

    /// <summary>
    /// True se o uso de itens deve estar bloqueado agora (PlayerItemUser). Só
    /// considera 'restrictItemUsage' se o desafio activo tiver 'hasTimeLimit'
    /// (ver tooltip de ChallengeDefinition.restrictItemUsage).
    /// </summary>
    public bool IsItemUsageRestricted()
    {
        var challenge = CurrentChallenge;
        return challenge != null && challenge.hasTimeLimit && challenge.restrictItemUsage;
    }

    /// <summary>
    /// True se "ability" deve estar bloqueada agora (AbilityRouter). Só
    /// considera 'restrictedAbilities' se o desafio activo tiver 'hasTimeLimit'
    /// (ver tooltip de ChallengeDefinition.restrictedAbilities).
    /// </summary>
    public bool IsAbilityRestricted(PrimaryAbility ability)
    {
        var challenge = CurrentChallenge;
        if (challenge == null || !challenge.hasTimeLimit || challenge.restrictedAbilities == null) return false;
        return challenge.restrictedAbilities.Contains(ability);
    }

    // ---------------- Provação de Apolo (Tarefa #15) ----------------

    /// <summary>True se o desafio activo é a Provação de Apolo (isApoloTrial) — morrer reinicia a prova em vez de morte normal.</summary>
    public bool IsApoloTrialActive => IsActive && CurrentChallenge.isApoloTrial;

    /// <summary>
    /// Reinicia o desafio activo do início (cronómetro, objectivos, condições
    /// de falha) sem o terminar — usado pela Provação de Apolo ao morrer
    /// (Tarefa #15, PlayerDeathHandler). Sem efeito se 'isApoloTrial' = false ou
    /// nenhum desafio activo.
    /// </summary>
    public void RestartApoloTrial()
    {
        if (!IsApoloTrialActive) return;

        var challenge = CurrentChallenge;
        ElapsedSeconds = 0f;
        _phaseElapsedSeconds = 0f;

        bool hasPhases = challenge.apoloPhases != null && challenge.apoloPhases.Count > 0;
        if (hasPhases)
        {
            // Reinicia sempre a partir da Fase 0.
            BeginPhase(0);
        }
        else
        {
            ResetObjectivesAndFailConditions(challenge);

            if (_hasEntryPosition)
            {
                var playerT = PlayerLocator.Find();
                if (playerT != null)
                {
                    var rb = playerT.GetComponent<Rigidbody2D>();
                    if (rb != null) { rb.position = _entryPosition; rb.linearVelocity = Vector2.zero; }
                    else playerT.position = _entryPosition;
                }
            }
        }
    }
}
